document.querySelector(".content > form").addEventListener("submit",e=>{async function t(){try{const e=await fetch(`${window.location.origin}/api/push`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({long_url:document.querySelector("#pasted_url").value,expiration:document.querySelector("form .expires").getAttribute("data-selected"),user_key:null})}),t=await e.json();if(!e.ok)throw new Error(t.error||"Bad response");if(!0!==t.success)throw new Error(t.response||"Failed to create paste");document.querySelector(".content").classList.add("shortened"),document.querySelector("#pasted_url").value=`${window.location.origin}/${t.response}`,document.querySelector("#pasted_url").setAttribute("data-value",`${window.location.origin}/${t.response}`),document.querySelector("#pasted_url").setAttribute("readonly","")}catch(e){console.error("Fetch Error:",e.message)}}e.preventDefault(),document.querySelector("body > .content").classList.contains("shortened")||t()}),document.addEventListener("click",e=>{e.target.closest(".expires span[data-value]")&&e.target.closest(".expires").setAttribute("data-selected",e.target.closest(".expires span[data-value]").getAttribute("data-value"))}),document.querySelector("body > .qr qr-code").addEventListener("codeRendered",()=>{document.querySelector(".qr qr-code").shadowRoot.querySelector("#qr-container").style="margin: 7px 0 0 7px",document.querySelector("body > .qr qr-code").animateQRCode("MaterializeIn")}),document.querySelector("body > .qr").addEventListener("click",()=>{document.querySelector("body > .qr").classList.remove("show")}),document.addEventListener("click",async e=>{if(!e.target.closest('form span[type="qr"]')&&!e.target.closest('form span[type="copy"]'))return;const t=document.querySelector("#pasted_url");if(e.target.closest('form span[type="qr"]')&&(document.querySelector("body > .qr").classList.add("show"),document.querySelector(".qr qr-code").setAttribute("contents",t.getAttribute("data-value"))),e.target.closest('form span[type="copy"]')){try{if(!navigator.clipboard)throw new Error("Clipboard API not supported");await navigator.clipboard.writeText(t.getAttribute("data-value")),t.value="copied url to clipboard"}catch(e){console.error("Failed to copy: ",e),t.value="failed to copy url to clipboard"}setTimeout(()=>{t.value=t.getAttribute("data-value")},850)}});